"""评标工作台全部可编辑的 AI 提示词模板。"""

from __future__ import annotations


PROMPT_TEMPLATE_SETTING = "evaluation_workbench_prompt_templates"


def _template(name: str, description: str, content: str, *placeholders: str) -> dict:
    return {"name": name, "description": description, "content": content, "placeholders": placeholders}


PROMPT_TEMPLATES = {
    "model_connection_test": _template("模型连接测试 · 任务", "模型配置页的最小连通性测试请求。", "请仅返回 JSON 对象：{\"message\":\"连接成功\"}"),
    "compare_ai_assessment": _template("文件查重 AI 复核 · 系统", "查重证据复核的角色与边界。", "你是招投标文件横向异常线索复核助手。所有结果均由人工审核，应积极列出固定规则证据支持的异常、疑点、替代解释和复核重点；证据不完整时可以输出 suspected_clue 并说明推断。不得编造证据，不得直接认定串通投标、废标或作出法律结论。"),
    "compare_ai_assessment_user": _template("文件查重 AI 复核 · 任务", "压缩证据包及 JSON 输出要求。", "请按固定规则复核以下压缩证据包，只返回 JSON：\n{\"assessments\":[{\"signal_id\":\"ID\",\"decision\":\"confirmed_clue|suspected_clue|excluded|unassessable\",\"risk_level\":\"low|medium|high\",\"confidence\":\"high|medium|low\",\"reason\":\"简洁理由\",\"suggested_check\":\"建议核验事项\"}]}\n\n判定含义：confirmed_clue 仅表示该异常线索有较充分证据；suspected_clue 表示仍有合理替代解释；excluded 表示现有证据更可能为模板/公共来源；unassessable 表示证据不足。不得输出串标成立、废标或扣分结论。\n证据包：{{packets}}", "packets"),
    "extract_rules": _template("评审规则提取 · 系统", "规则提取的角色与证据边界。", "你是招投标评审规则提取助手。只能根据给出的招标文件原文提取明确、可核验的规则，不得编造。只能依据给出的招标文件原文，不得编造；必须遵守输出 JSON 结构。"),
    "extract_rules_user": _template("评审规则提取 · 任务", "招标原文、评分覆盖清单与完整输出规范。", "请从以下招标文件原文提取可由 AI 审查的评标规则，只返回一个合法 JSON 对象：\n{\"rules\":[{\"category\":\"qualification|compliance|substantive|rejection|objective|subjective\",\"title\":\"简明规则名称\",\"check_rule\":\"面向投标文件的明确检查指令\",\"source_text\":\"招标原文短摘录\",\"ocr_required\":false,\"scoring\":{\"max_score\":数字,\"kind\":\"boolean|manual\"}}]}\n\n严格要求：不得使用 Markdown 或在 JSON 前后添加说明；不得逐条复述招标原文；同类要求合并为一条规则。{{limits}}\n{{score_requirement}}\n只保留能通过已上传投标文件中可检索的文字、表格或元数据核验的事项，规则必须明确且能据文件内容判断。请根据完整语境判断，不要输出密封与递交要求、响应文件份数或电子版要求、递交地点/时间、开标现场、线下原件、纸质材料、投标文件本身无法体现的签收事项，以及其他无法仅凭投标文件核验的事项；但“投标截止日前若干年内的业绩”等仅用于界定业绩有效期、且可由投标文件证明的内容必须保留。若规则的关键证据只能依赖扫描图片、证照图片、签章或手写内容识别，请将 ocr_required 设为 true；其余为 false。\n\n分类说明：qualification 为资格性；compliance 为符合性；substantive 为实质性；rejection 为无效投标/废标；objective 为客观分；subjective 为主观分。objective 和 subjective 必须填写 scoring.max_score，且只能填写招标原文明确规定的满分；没有明确满分时不要输出为评分项。objective 仅“满足即满分”时 kind 为 boolean，分档、数量、累计或人工判断评分时 kind 为 manual；subjective 的 kind 为 manual。非评分项省略 scoring。\n\n评分条款覆盖清单：\n{{score_audit}}\n\n招标文件原文：\n{{text}}", "limits", "score_requirement", "score_audit", "text"),
    "extract_rules_supplement_user": _template("评审规则提取 · 评分补充", "遗漏评分条款的补充提取。", "仅根据以下评分条款，补充主规则提取遗漏的明确评分项。只返回合法 JSON：\n{\"rules\":[{\"category\":\"objective|subjective\",\"title\":\"简明规则名称\",\"check_rule\":\"面向投标文件的明确检查指令\",\"source_text\":\"原文短摘录\",\"ocr_required\":false,\"scoring\":{\"max_score\":数字,\"kind\":\"boolean|manual\"}}]}\n\n已有评分规则：{{existing_rules}}\n必须仅返回缺失项，不得重复已有项；每个明确评分条款都要覆盖。objective 和 subjective 都必须有 scoring.max_score，且仅能填写原文明确的满分。不得使用 Markdown 或添加说明；title 最多 30 字，check_rule 最多 90 字，source_text 最多 120 字。\n\n评分条款：\n{{packet_text}}", "existing_rules", "packet_text"),
    "review_documents": _template("单项文件审查 · 系统", "兼容单项审查流程的角色和边界。", "你是招投标电子文件审查助手。所有结果均由人工审核，应逐项引用可见原文并积极给出最可能的响应判断、疑点和风险。可以提出暂定推断，但必须区分原文事实与推断，不得编造图片、签字、盖章或线下材料。"),
    "review_documents_user": _template("单项文件审查 · 任务", "规则、投标文件及 JSON 输出要求。", "请逐条审查投标文件。返回 JSON：\n{\"results\":[{\"rule_id\":\"规则ID\",\"status\":\"satisfied|not_satisfied|partial|not_found|manual|ocr_required\",\"evidence\":\"投标文件原文摘录\",\"page_hint\":null,\"reason\":\"简洁判断理由\",\"risk_level\":\"low|medium|high\",\"confidence\":\"high|medium|low\",\"evidence_quality\":\"sufficient|limited|missing\"}]}\n\n对于 ocr_required=true 的规则，当前系统未执行 OCR；若关键证据仅存在于图片、签章、证照或手写内容，必须返回 ocr_required，不能据此返回不满足。\n规则：\n{{rules}}\n\n投标文件：{{document_name}}；投标人：{{bidder_name}}\n原文：\n{{text}}", "rules", "document_name", "bidder_name", "text"),
    "score_objective": _template("客观分辅助评分 · 系统", "兼容客观评分流程的角色与边界。", "你是招投标客观评分辅助助手。应依据评分规则和投标文件原文积极提取证据并给出明确的 AI 建议分。允许提出疑点和暂定判断，所有结果均由人工复核；不得编造原文、页码或材料，不得超出评分上限。"),
    "score_objective_user": _template("客观分辅助评分 · 任务", "客观评分规则、投标文件及 JSON 输出要求。", "返回 JSON：{\"results\":[{\"rule_id\":\"规则ID\",\"met\":true|false|null,\"suggested_score\":数字或null,\"matched_count\":数字或null,\"needs_ocr\":true|false,\"evidence_items\":[{\"name\":\"证据名称\",\"page_hint\":\"页码\",\"validity\":\"valid|uncertain|invalid\",\"reason\":\"逐项理由\"}],\"evidence\":\"原文摘录\",\"calculation\":\"计分过程\",\"reason\":\"判断理由\",\"confidence\":\"high|medium|low\"}]}。满足即满分项可同时返回 met；数量、累计、分档等规则必须尽量给出 matched_count、计算过程和 suggested_score。证据不完全或需要 OCR 时仍应根据可见材料给出暂定建议分，并将 needs_ocr 设为 true，不要仅因需要人工复核而留空。不得超过 scoring.max_score。\n评分规则：{{rules}}\n投标文件：{{document_name}}\n全文或证据包：\n{{text}}", "rules", "document_name", "text"),
    "score_subjective": _template("主观分辅助评分 · 系统", "兼容主观评分流程的角色与边界。", "你是招投标主观评分辅助助手。应依据评分规则和投标文件原文给出有证据支撑的评分建议。只能依据评分规则与投标文件原文，不得编造材料或超出评分上限。"),
    "score_subjective_user": _template("主观分辅助评分 · 任务", "主观评分规则、投标文件及 JSON 输出要求。", "返回 JSON：{\"results\":[{\"rule_id\":\"规则ID\",\"suggested_score\":数字,\"needs_ocr\":true|false,\"evidence\":\"原文摘录\",\"reason\":\"得扣分理由\",\"confidence\":\"high|medium|low\"}]}。分数不得超出规则 scoring.max_score。证据不完全或需要 OCR 时仍应依据可见材料给出暂定建议分，并用 needs_ocr 标记核验需要；不得编造证据。\n评分规则：{{rules}}\n投标文件：{{document_name}}\n原文：\n{{text}}", "rules", "document_name", "text"),
    "evaluate_all": _template("综合评审 · 系统", "综合评审的角色与边界。", "你是招投标综合评审辅助助手。准确发现问题和完整提出建议优先于节省输出。所有结果均由人工最终审核，因此应积极给出最可能的结论、风险、证据、理由和建议分，可明确提出疑点与暂定推断；但必须区分原文事实与 AI 推断，不得编造原文、页码、签章或线下材料。"),
    "evaluate_all_scope_profile": _template("综合评审 · 项目范围画像 · 系统", "从招标文件建立全项目一致性审查基准。", "你是招投标项目范围分析助手。只能根据招标文件、已确认规则及项目名称归纳明确的项目范围；不要猜测未出现的限制，不要评价投标文件，也不要把潜在问题写成既成事实。"),
    "evaluate_all_scope_profile_user": _template("综合评审 · 项目范围画像 · 任务", "在综合评审前一次性建立项目主体、技术、设备和交付范围的紧凑基准。", "请只返回合法 JSON：{\"project_identity\":\"项目主体、采购对象和目标的简洁描述\",\"scope_summary\":\"工作范围摘要\",\"service_targets\":[\"服务对象或应用场景\"],\"core_tasks\":[\"核心任务\"],\"technical_topics\":[\"技术主题或方法\"],\"equipment_or_materials\":[\"明确要求或相关的设备/材料类别\"],\"deliverables\":[\"成果或交付物\"],\"standards_or_rules\":[\"适用标准、法规或规范\"],\"regions\":[\"实施地域\"],\"keywords\":[\"有区分度的项目词\"]}。字段可为空数组或空字符串；不要为了填满字段补造信息。\n项目名称：{{project_name}}\n已确认规则：{{rules}}\n招标文件依据：\n{{tender_text}}", "project_name", "rules", "tender_text"),
    "json_repair": _template("结构化结果修复 · 系统", "仅修复模型已经生成的 JSON 语法，不重新进行业务判断。", "你是 JSON 结构修复器。只修复给定响应中的语法、转义、括号和顶层结构；保留已有字段和值，不新增业务事实，不解释，不输出 Markdown。"),
    "json_repair_user": _template("结构化结果修复 · 任务", "格式异常时只回传模型响应本身，避免重新发送整份投标文件。", "请把下列模型响应修复为一个可解析的 JSON 对象。预期顶层字段：{{expected_field}}。只输出修复后的 JSON；不得补造响应中不存在的证据、分数或结论。\n\n待修复响应：\n{{raw_response}}", "expected_field", "raw_response"),
    "evaluate_all_full_scan_user": _template("综合评审 · 全文证据扫描", "每个连续页块只扫描一次，同时建立规则证据和项目范围偏离候选。", "{{retry_note}}这是投标文件全文证据扫描的一部分。完成两类独立工作：一、将当前页块与规则目录逐项对照，返回规则证据；二、将当前页块与项目范围画像对照，发现任何可能与本项目不一致的主体、地域、技术主题、设备/材料、标准法规、服务对象、成果交付、时间地点或其他内容。范围偏离只报告可复核候选，不作废标或最终结论；外地业绩、注册地址、公司介绍、合理引用和可选方案不应仅因不同而认定异常。\n只返回合法 JSON：{\"matches\":[[\"规则ID\",\"页码\",\"原文短摘录\",\"supports|contradicts|partial|suspected\"]],\"scope_anomalies\":[[\"页码\",\"开放类型描述\",\"high|medium|low\",\"原文短摘录\",\"与项目范围的关系或疑点\"]]}。matches 每个数组恰好四项、最多24条；scope_anomalies 每个数组恰好五项、最多8条；原文短摘录最多80字，关系或疑点最多60字。范围候选只写原文与范围的直接关系，不写重复解释。没有候选时对应数组返回空数组。不得输出 Markdown、说明文字、编造页码或原文。\n项目范围画像：{{project_scope}}\n规则目录：{{rules}}\n投标文件：{{document_name}}；投标人：{{bidder_name}}；当前范围：{{chunk_label}}\n当前连续页块：\n{{text}}", "retry_note", "project_scope", "rules", "document_name", "bidder_name", "chunk_label", "text"),
    "evaluate_all_review_user": _template("综合评审 · 审查规则组", "综合评审中资格、符合、实质性/废标规则组的任务提示词。", "{{retry_note}}请根据全文覆盖扫描候选、项目范围画像、范围偏离候选、重点原文和规则要求逐条给出明确的 AI 审查建议，只返回 JSON：\n{\"results\":[{\"rule_id\":\"规则ID\",\"status\":\"satisfied|not_satisfied|partial|not_found|manual|ocr_required\",\"evidence\":\"投标文件原文摘录\",\"page_hint\":null,\"reason\":\"判断理由；可列出疑点和推断\",\"risk_level\":\"low|medium|high\",\"confidence\":\"high|medium|low\",\"evidence_quality\":\"sufficient|limited|missing\"}]}\n每条 evidence 仅保留最直接的原文和页码，最多180字；reason 只写“事实→规则→建议”的一句话，最多90字。全文扫描未报告候选时，也应给出“全文扫描未发现相应异常/证据”的最可能建议，不要默认转为人工核验。范围偏离候选可能涉及任何不属于本项目的主体、技术、设备、标准、服务对象、交付物、时间地点或其他内容；它们只是线索，必须结合原页、项目范围和规则判断，不得把合理业绩、地址、公司介绍或引用材料直接认定为异常。对图片、签章、证照或手写内容可给出暂定判断并说明需 OCR；只有确实无法作出任何建议时才返回 manual。不得编造原文。\n规则组：{{rules}}\n投标文件：{{document_name}}；投标人：{{bidder_name}}\n全文扫描证据包、项目范围画像与重点原文：\n{{text}}", "retry_note", "rules", "document_name", "bidder_name", "text"),
    "evaluate_all_objective_user": _template("综合评审 · 客观评分规则组", "综合评审中客观评分规则组的任务提示词。", "{{retry_note}}请根据全文覆盖扫描候选、重点原文和评分规则给出明确的 AI 建议分，只返回 JSON：\n{\"results\":[{\"rule_id\":\"规则ID\",\"met\":true|false|null,\"suggested_score\":数字或null,\"matched_count\":数字或null,\"needs_ocr\":true|false,\"evidence_items\":[{\"name\":\"项目或证据名称\",\"page_hint\":\"页码\",\"validity\":\"valid|uncertain|invalid\",\"reason\":\"逐项判断\"}],\"evidence\":\"原文摘录\",\"calculation\":\"计分过程\",\"reason\":\"判断理由\",\"confidence\":\"high|medium|low\"}]}\n满足即满分项可返回 met；数量、累计、分档规则必须尽量返回 matched_count、逐项证据、计算过程和 suggested_score。逐项 reason、calculation 与总 reason 均只保留必要事实和计算关系，不重复解释；evidence 最多180字、总 reason 最多100字。全文扫描未发现相关材料时也应根据评分规则给出最可能的建议（通常为0分）并说明依据。需要 OCR 或证据不完全时仍应给出暂定建议分并标记 needs_ocr，不得仅因需要人工审核而留空；不得超过 scoring.max_score，不得编造证据。\n评分规则组：{{rules}}\n投标文件：{{document_name}}；投标人：{{bidder_name}}\n全文扫描证据包与重点原文：\n{{text}}", "retry_note", "rules", "document_name", "bidder_name", "text"),
    "evaluate_all_subjective_user": _template("综合评审 · 主观评分规则组", "综合评审中主观评分规则组的任务提示词。", "{{retry_note}}请根据全文覆盖扫描候选、重点章节和评分规则大胆给出有依据的评分建议，只返回 JSON：\n{\"results\":[{\"rule_id\":\"规则ID\",\"suggested_score\":数字,\"needs_ocr\":true|false,\"evidence\":\"原文摘录\",\"reason\":\"得扣分理由及疑点\",\"confidence\":\"high|medium|low\"}]}\n每条 evidence 仅保留最直接的原文和页码，最多180字；reason 以一句“事实→评分规则→建议分”说明，最多100字。所有结果均由人工审核；证据不完整或需要 OCR 时仍应根据可见材料给出暂定分并说明核验点，不要仅因不确定而留空。建议分不得超过 scoring.max_score，不得编造证据。\n评分规则组：{{rules}}\n投标文件：{{document_name}}；投标人：{{bidder_name}}\n全文扫描证据包与重点原文：\n{{text}}", "retry_note", "rules", "document_name", "bidder_name", "text"),
    "evaluate_all_cross_bid_price_user": _template("综合评审 · 跨投标人价格评分", "需要比较全部投标报价时，在单份文件评审后统一计算价格分。", "请依据评分规则，同时比较全部投标人的报价证据并给出 AI 建议分。只返回 JSON：\n{\"results\":[{\"document_id\":\"文件ID\",\"rule_id\":\"规则ID\",\"quoted_price\":数字或null,\"suggested_score\":数字或null,\"evidence\":\"报价原文及页码\",\"calculation\":\"基准价和计分过程\",\"reason\":\"判断理由\",\"confidence\":\"high|medium|low\"}]}\n必须覆盖每个文件和每条规则；先核对币种、报价口径、最高限价及异常报价，再按原规则计算。所有结果由人工审核，可给出明确的暂定分和疑点，但不得编造报价或超出 scoring.max_score。\n价格评分规则：{{rules}}\n全部投标人报价证据包：\n{{documents}}", "rules", "documents"),
    "evaluate_all_user": _template("综合评审 · 任务", "兼容综合审查、评分及 JSON 输出要求。", "{{retry_note}}对同一份投标文件完成下列三类工作，并只返回一个合法 JSON 对象：\n{\"review_results\":[{\"rule_id\":\"规则ID\",\"status\":\"satisfied|not_satisfied|partial|not_found|manual|ocr_required\",\"evidence\":\"原文摘录\",\"page_hint\":null,\"reason\":\"理由与疑点\",\"risk_level\":\"low|medium|high\",\"confidence\":\"high|medium|low\",\"evidence_quality\":\"sufficient|limited|missing\"}],\"objective_scores\":[{\"rule_id\":\"规则ID\",\"met\":true|false|null,\"suggested_score\":数字或null,\"matched_count\":数字或null,\"needs_ocr\":true|false,\"evidence\":\"原文摘录\",\"calculation\":\"计分过程\",\"reason\":\"判断理由\",\"confidence\":\"high|medium|low\"}],\"subjective_scores\":[{\"rule_id\":\"规则ID\",\"suggested_score\":数字,\"needs_ocr\":true|false,\"evidence\":\"原文摘录\",\"reason\":\"得扣分理由\",\"confidence\":\"high|medium|low\"}]}\n\n严格要求：不得使用 Markdown 代码块、不得在 JSON 前后添加说明、所有字符串必须使用标准 JSON 双引号和转义。{{limits}}\n审查规则：{{review_rules}}\n客观评分规则：{{objective_rules}}\n主观评分规则：{{subjective_rules}}\n所有结果均由人工审核，应积极给出最可能的判断、疑点和建议分。需要 OCR 或证据不完整时仍可基于可见材料给暂定建议并明确核验点；不得编造证据，评分不得超过 scoring.max_score。\n投标文件：{{document_name}}；投标人：{{bidder_name}}\n原文：\n{{text}}", "retry_note", "limits", "review_rules", "objective_rules", "subjective_rules", "document_name", "bidder_name", "text"),
}


def default_template(template_id: str) -> str:
    return PROMPT_TEMPLATES[template_id]["content"]
